#include <stdio.h>
#include <string.h>

char winChar(char c){
    if(c=='R') return 'P';
    if(c=='P') return 'S';
    return 'R'; // c=='S'
}

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        char A[100005]; scanf("%s",A);
        int need = N/2 + 1; // floor(N/2)+1
        char ans[100005];
        for(int i=0;i<N;i++){
            char w = winChar(A[i]);
            for(char c='P'; c<='S'; c++){
                if(c!='P' && c!='R' && c!='S') continue; // skip non‑valid chars
                int need2 = need - (c==w);
                int rem = N - i - 1;
                if(need2>=0 && need2<=rem){
                    ans[i]=c;
                    need = need2;
                    break;
                }
            }
        }
        ans[N]='\0';
        printf("%s\n",ans);
    }
    return 0;
}

