#!/usr/bin/env python3
import sys

def win_char(c):
    return {'R':'P','P':'S','S':'R'}[c]

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        A = next(it).strip()
        need = N//2 + 1
        ans = []
        for i,ch in enumerate(A):
            w = win_char(ch)
            for c in ('P','R','S'):
                need2 = need - (1 if c==w else 0)
                rem = N - i - 1
                if need2 >= 0 and need2 <= rem:
                    ans.append(c)
                    need = need2
                    break
        out_lines.append(''.join(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

